Running command: cat > /workspace/answer.json << 'EOF'
{
  "legacy_alerting_engine": {
    "description": "The legacy alerting engine stored dashboard-based alert rules in the 'alert' table. In this version of Grafana, the legacy alerting engine runtime has been fully removed (no pkg/services/alerting/ directory exists). Only the database schema definition and migration artifacts remain.",
    "files": [
      {
        "path": "pkg/services/sqlstore/migrations/alert_mig.go",
        "role": "Defines the SQL schema for the legacy 'alert' table (dashboard alerts), 'alert_rule_tag', 'alert_notification', 'alert_notification_state' tables. This is the authoritative schema for the legacy alerting system.",
        "key_symbols": ["addAlertMigrations", "alertV1 (Table: 'alert')", "alert_notification", "alert_notification_state"]
      }
    ]
  },
  "unified_alerting_engine": {
    "description": "The unified alerting (ngalert) engine is the current alerting system in Grafana. It stores alert rules in the 'alert_rule' table and is orchestrated by the AlertNG service.",
    "files": [
      {
        "path": "pkg/services/ngalert/ngalert.go",
        "role": "Main entry point and service wiring for the unified alerting engine (AlertNG). Wires together the scheduler, evaluator, notifier, state manager, API, and store.",
        "key_symbols": ["AlertNG", "ProvideService"]
      },
      {
        "path": "pkg/services/ngalert/store/alert_rule.go",
        "role": "Core CRUD implementation for unified alert rules against the 'alert_rule' and 'alert_rule_version' tables. Implements GetAlertRuleByUID, InsertAlertRules, UpdateAlertRules, DeleteAlertRulesByUID, ListAlertRules, GetAlertRulesKeysForScheduling, etc.",
        "key_symbols": ["DBstore", "GetAlertRuleByUID", "InsertAlertRules", "UpdateAlertRules", "DeleteAlertRulesByUID", "ListAlertRules", "GetAlertRulesKeysForScheduling"]
      },
      {
        "path": "pkg/services/ngalert/store/database.go",
        "role": "Defines the DBstore struct (unified alert rule store), the AlertingStore interface, and the ProvideDBStore constructor. DBstore is the single store implementation used by all ngalert subsystems.",
        "key_symbols": ["DBstore", "AlertingStore", "ProvideDBStore"]
      },
      {
        "path": "pkg/services/ngalert/models/alert_rule.go",
        "role": "Defines the AlertRule model for unified alerting, including migration-related label constants (MigratedLabelPrefix, MigratedUseLegacyChannelsLabel, MigratedContactLabelPrefix, etc.) used to tag rules that were migrated from legacy alerting.",
        "key_symbols": ["AlertRule", "MigratedLabelPrefix", "MigratedUseLegacyChannelsLabel", "MigratedContactLabelPrefix", "MigratedSilenceLabelErrorKeepState", "MigratedSilenceLabelNodataKeepState"]
      },
      {
        "path": "pkg/services/ngalert/schedule/",
        "role": "Directory containing the alert rule scheduler and evaluator (schedule.go, alert_rule.go, recording_rule.go). Responsible for ticking alert rules and dispatching evaluations.",
        "key_symbols": ["SchedulerCfg", "schedule"]
      },
      {
        "path": "pkg/services/ngalert/store/instance_database.go",
        "role": "Stores and retrieves alert instances (firing state) in the 'alert_instance' table.",
        "key_symbols": ["InstanceDBStore", "SaveAlertInstance", "DeleteAlertInstances"]
      },
      {
        "path": "pkg/services/ngalert/store/alertmanager.go",
        "role": "Stores and retrieves Alertmanager configurations in the 'alert_configuration' and 'alert_configuration_history' tables.",
        "key_symbols": ["GetLatestAlertmanagerConfiguration", "GetAllLatestAlertmanagerConfiguration", "SaveAlertmanagerConfiguration"]
      }
    ]
  },
  "migration_script": {
    "description": "The migration from legacy dashboard-based alert rules to unified alerting format is implemented as a series of SQL schema migrations and code migrations in the pkg/services/sqlstore/migrations/ualert/ package. The migration title is 'move dashboard alerts to unified alerting'. The migration service tracks state in the KV store under namespace 'ngalert.migration'.",
    "files": [
      {
        "path": "pkg/services/sqlstore/migrations/ualert/ualert.go",
        "role": "Main migration orchestrator. Defines migTitle='move dashboard alerts to unified alerting', MigrationError type, FixEarlyMigration (fixes pre-8.2 UA configs with org_id=0), AddDashboardUIDPanelIDMigration (backfills dashboard_uid and panel_id on alert_rule from annotations), and upgradeNgAlerting (assigns alert_configuration records to correct orgs and moves alertmanager files).",
        "key_symbols": ["migTitle", "MigrationError", "FixEarlyMigration", "AddDashboardUIDPanelIDMigration", "upgradeNgAlerting", "updateDashboardUIDPanelIDMigration"]
      },
      {
        "path": "pkg/services/sqlstore/migrations/ualert/tables.go",
        "role": "Defines all SQL schema migrations for unified alerting tables: alert_rule, alert_rule_version, alert_configuration, alert_configuration_history, alert_instance, ngalert_configuration, and all their column/index additions over time.",
        "key_symbols": ["AddTablesMigrations", "alertRule (Table: 'alert_rule')", "alertRuleVersion", "alertConfiguration"]
      },
      {
        "path": "pkg/services/sqlstore/migrations/ualert/migration_service_migration.go",
        "role": "Moves the legacy alert migration status from the migration_log table to the kv_store. Defines KVNamespace='ngalert.migration' used by the migration service to track per-org migration state.",
        "key_symbols": ["MigrationServiceMigration", "KVNamespace", "migrationLogToKVStore"]
      },
      {
        "path": "pkg/services/sqlstore/migrations/ualert/created_folders_mig.go",
        "role": "Migrates the record of folders created during legacy alert migration from Dashboard.created_by=-8 marker to the kv_store. Part of the legacy-to-unified migration bookkeeping.",
        "key_symbols": ["CreatedFoldersMigration", "createdFoldersToKVStore"]
      },
      {
        "path": "pkg/services/sqlstore/migrations/ualert/org_upgrade_state_mig.go",
        "role": "Creates per-org KV store entries tracking whether each org has been migrated from Legacy to UnifiedAlerting. Defines the Legacy and UnifiedAlerting alertingType constants used to detect transitions.",
        "key_symbols": ["CreateOrgMigratedKVStoreEntries", "Legacy", "UnifiedAlerting", "createOrgMigratedKVStoreEntries"]
      },
      {
        "path": "pkg/services/sqlstore/migrations/ualert/rule_group_index_migration.go",
        "role": "Backfills the rule_group_idx column on existing alert_rule rows after the column was added, assigning sequential indices within each rule group.",
        "key_symbols": ["UpdateRuleGroupIndexMigration", "updateRuleGroupIndex"]
      },
      {
        "path": "pkg/services/sqlstore/migrations/alert_mig.go",
        "role": "Defines the legacy 'alert' table schema (source of migration). The migration reads from this table to convert dashboard alerts into unified alert_rule rows.",
        "key_symbols": ["addAlertMigrations"]
      },
      {
        "path": "pkg/services/sqlstore/migrations/migrations.go",
        "role": "Top-level migration orchestrator that registers all migrations in order, including both addAlertMigrations (legacy) and all ualert.* migrations (unified). Shows the full migration sequence.",
        "key_symbols": ["OSSMigrations", "AddMigration"]
      }
    ]
  }
}
EOF
echo "Done"

