any{\"__default__.tmpl\": nil, \"silences\": nil, \"notifications\": nil}\n177: \talertingDir := filepath.Join(migrator.Cfg.DataPath, \"alerting\")\n178: \n179: \t// do not fail if something goes wrong because these files are not used anymore. the worst that can happen is that we leave some leftovers behind\n180: \tdeleteFile := func(fileName string) {\n181: \t\tpath := filepath.Join(alertingDir, fileName)\n182: \t\tmigrator.Logger.Info(\"Deleting alerting configuration file\", \"file\", fileName)\n183: \t\terr := os.Remove(path)\n184: \t\tif err != nil {\n185: \t\t\tmigrator.Logger.Warn(\"Failed to delete file\", \"file\", path, \"error\", err)\n186: \t\t}\n187: \t}\n188: \n189: \tmoveFile := func(fileName string) {\n190: \t\talertingOrgDir := filepath.Join(alertingDir, strconv.FormatInt(orgId, 10))\n191: \t\tif err := os.MkdirAll(alertingOrgDir, 0750); err != nil {\n192: \t\t\tmigrator.Logger.Error(\"Failed to create alerting directory for organization. Skip moving the file and delete it instead\", \"target_dir\", alertingOrgDir, \"org_id\", orgId, \"error\", err, \"file\", fileName)\n193: \t\t\tdeleteFile(fileName)\n194: \t\t\treturn\n195: \t\t}\n196: \t\terr := os.Rename(filepath.Join(alertingDir, fileName), filepath.Join(alertingOrgDir, fileName))\n197: \t\tif err != nil {\n198: \t\t\tmigrator.Logger.Error(\"Failed to move alertmanager configuration file to organization.\", \"source_dir\", alertingDir, \"target_dir\", alertingOrgDir, \"org_id\", orgId, \"error\", err, \"file\", fileName)\n199: \t\t\tdeleteFile(fileName)\n200: \t\t}\n201: \t}\n202: \n203: \tentries, err := os.ReadDir(alertingDir)\n204: \tif err != nil {\n205: \t\tif !os.IsNotExist(err) {\n206: \t\t\tkeys := make([]string, 0, len(knownFiles))\n207: \t\t\tfor key := range knownFiles {\n208: \t\t\t\tkeys = append(keys, key)\n209: \t\t\t}\n210: \t\t\tmigrator.Logger.Warn(\"Failed to clean up alerting directory. There may be files that are not used anymore.\", \"path\", alertingDir, \"files_to_delete